#ifndef TOP_P_SAMPLING_KERNEL_H
#define TOP_P_SAMPLING_KERNEL_H

#include <cuda_runtime.h>
#include <stdint.h>

// Constants for A800 optimization
constexpr int VOCAB_SIZE = 151936;
constexpr int BLOCK_SIZE = 256;
constexpr int WARP_SIZE = 32;

// Kernel declarations
__global__ void top_p_sampling_kernel(
    const float* __restrict__ probs,
    const float* __restrict__ top_p,
    int64_t* __restrict__ samples,
    int batch_size,
    int vocab_size
);

// Host function to launch kernel
void launch_top_p_sampling(
    const float* probs,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    int vocab_size,
    cudaStream_t stream = 0
);

// Device helper function declarations
__device__ __forceinline__ int64_t device_argmax(const float* probs, int vocab_size);
__device__ __forceinline__ float device_rand(unsigned int seed, int batch_idx);
__device__ __forceinline__ int64_t device_sample_multinomial(const float* probs, int vocab_size, float rand_val);

#endif // TOP_P_SAMPLING_KERNEL_H

#include "kernel.h"
#include <device_launch_parameters.h>
#include <cuda_runtime.h>
#include <math.h>
#include <thrust/device_ptr.h>
#include <thrust/sort.h>
#include <thrust/execution_policy.h>
#include <thrust/sequence.h>
#include <thrust/copy.h>
#include <thrust/transform.h>
#include <thrust/iterator/counting_iterator.h>
#include <thrust/iterator/transform_iterator.h>

// Device function: Find argmax
__device__ __forceinline__ int64_t device_argmax(const float* probs, int vocab_size) {
    int max_idx = 0;
    float max_val = probs[0];
    for (int i = 1; i < vocab_size; i++) {
        if (probs[i] > max_val) {
            max_val = probs[i];
            max_idx = i;
        }
    }
    return max_idx;
}

// Device function: Generate random number using xorshift
__device__ __forceinline__ unsigned int xorshift32(unsigned int seed) {
    seed ^= seed << 13;
    seed ^= seed >> 17;
    seed ^= seed << 5;
    return seed;
}

__device__ __forceinline__ float device_rand(unsigned int seed, int batch_idx) {
    seed = xorshift32(seed + batch_idx * 12345);
    seed = xorshift32(seed + 67890);
    return ((float)(seed & 0x7FFFFFFF)) / 0x7FFFFFFF;
}

// Device function: Sample from multinomial distribution
__device__ __forceinline__ int64_t device_sample_multinomial(const float* probs, int vocab_size, float rand_val) {
    float cumsum = 0.0f;
    for (int i = 0; i < vocab_size; i++) {
        cumsum += probs[i];
        if (rand_val < cumsum) {
            return i;
        }
    }
    return vocab_size - 1;
}

// Main CUDA kernel - each thread processes one batch item
__global__ void top_p_sampling_kernel(
    const float* __restrict__ probs,
    const float* __restrict__ top_p,
    int64_t* __restrict__ samples,
    int batch_size,
    int vocab_size
) {
    int batch_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (batch_idx >= batch_size) return;

    const float* row = probs + batch_idx * vocab_size;
    float top_p_val = top_p[batch_idx];

    // Case 1: top_p <= 0.0, use argmax
    if (top_p_val <= 0.0f) {
        samples[batch_idx] = device_argmax(row, vocab_size);
        return;
    }

    // Case 2: top_p >= 1.0, use regular multinomial
    if (top_p_val >= 1.0f) {
        unsigned int seed = (unsigned int)(batch_idx);
        float rand_val = device_rand(seed, batch_idx);
        samples[batch_idx] = device_sample_multinomial(row, vocab_size, rand_val);
        return;
    }

    // Case 3: top_p in (0, 1), perform nucleus sampling
    // Allocate temporary storage for sorting using thrust
    // We need to sort probabilities and keep track of original indices

    // Create temporary arrays in global memory for this thread
    // Note: In production, we would use a pre-allocated buffer pool
    float* temp_probs = (float*)malloc(vocab_size * sizeof(float));
    int* temp_indices = (int*)malloc(vocab_size * sizeof(int));

    if (!temp_probs || !temp_indices) {
        // Fallback to argmax if allocation fails
        samples[batch_idx] = device_argmax(row, vocab_size);
        return;
    }

    // Copy data to temporary storage
    for (int i = 0; i < vocab_size; i++) {
        temp_probs[i] = row[i];
        temp_indices[i] = i;
    }

    // Sort by probability descending using thrust
    thrust::device_ptr<float> d_probs(temp_probs);
    thrust::device_ptr<int> d_indices(temp_indices);

    thrust::sort_by_key(
        thrust::seq,
        d_probs,
        d_indices,
        thrust::greater<float>()
    );

    // Find top-p cutoff
    float cumsum = 0.0f;
    int cutoff = 0;
    for (int i = 0; i < vocab_size; i++) {
        cumsum += temp_probs[i];
        if (cumsum > top_p_val) {
            cutoff = i + 1;
            break;
        }
    }

    // If cutoff is 0, use argmax
    if (cutoff == 0) {
        samples[batch_idx] = temp_indices[0];
        free(temp_probs);
        free(temp_indices);
        return;
    }

    // Renormalize the top cutoff probabilities
    float sum = 0.0f;
    for (int i = 0; i < cutoff; i++) {
        sum += temp_probs[i];
    }

    if (sum <= 0.0f) {
        samples[batch_idx] = temp_indices[0];
        free(temp_probs);
        free(temp_indices);
        return;
    }

    // Sample from the filtered distribution
    unsigned int seed = (unsigned int)(batch_idx);
    float rand_val = device_rand(seed, batch_idx);
    cumsum = 0.0f;
    int sampled_idx = cutoff - 1;
    for (int i = 0; i < cutoff; i++) {
        cumsum += temp_probs[i] / sum;
        if (rand_val < cumsum) {
            sampled_idx = i;
            break;
        }
    }
    samples[batch_idx] = temp_indices[sampled_idx];

    free(temp_probs);
    free(temp_indices);
}

// Host function to launch kernel
void launch_top_p_sampling(
    const float* probs,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    int vocab_size,
    cudaStream_t stream
) {
    // Configure kernel launch
    int threads_per_block = BLOCK_SIZE;
    int num_blocks = (batch_size + threads_per_block - 1) / threads_per_block;

    // Limit blocks to avoid too many concurrent threads
    num_blocks = min(num_blocks, 1024);

    // Launch kernel
    top_p_sampling_kernel<<<num_blocks, threads_per_block, 0, stream>>>(
        probs, top_p, samples, batch_size, vocab_size
    );

    // Check for launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        // Error will be handled by caller
    }
}

#include <torch/extension.h>
#include "kernel.h"
#include <cuda_runtime.h>
#include <stdexcept>
#include <iostream>

// Validate tensor properties
void validate_tensor(const torch::Tensor& tensor, const std::string& name, 
                     torch::ScalarType expected_dtype, torch::DeviceType expected_device,
                     int expected_dim = -1) {
    if (!tensor.is_cuda()) {
        throw std::runtime_error(name + " must be on CUDA device");
    }
    if (tensor.scalar_type() != expected_dtype) {
        throw std::runtime_error(name + " must have dtype " + 
                                 torch::str(expected_dtype) + ", got " + 
                                 torch::str(tensor.scalar_type()));
    }
    if (expected_dim >= 0 && tensor.dim() != expected_dim) {
        throw std::runtime_error(name + " must have " + std::to_string(expected_dim) + 
                                 " dimensions, got " + std::to_string(tensor.dim()));
    }
}

// Main run function with output tensor parameter
void run(torch::Tensor probs, torch::Tensor top_p, torch::Tensor samples) {
    // Validate inputs
    validate_tensor(probs, "probs", torch::kFloat32, torch::kCUDA, 2);
    validate_tensor(top_p, "top_p", torch::kFloat32, torch::kCUDA, 1);
    validate_tensor(samples, "samples", torch::kInt64, torch::kCUDA, 1);

    // Get dimensions
    int64_t batch_size = probs.size(0);
    int64_t vocab_size = probs.size(1);

    // Validate vocab_size matches expected constant
    if (vocab_size != 151936) {
        throw std::runtime_error("vocab_size must be 151936, got " + 
                                 std::to_string(vocab_size));
    }

    // Validate top_p size matches batch_size
    if (top_p.size(0) != batch_size) {
        throw std::runtime_error("top_p batch size must match probs batch size");
    }

    // Validate samples size matches batch_size
    if (samples.size(0) != batch_size) {
        throw std::runtime_error("samples batch size must match probs batch size");
    }

    // Validate batch_size is positive
    if (batch_size <= 0) {
        throw std::runtime_error("batch_size must be positive, got " + 
                                 std::to_string(batch_size));
    }

    // Get raw pointers
    const float* probs_ptr = probs.data_ptr<float>();
    const float* top_p_ptr = top_p.data_ptr<float>();
    int64_t* samples_ptr = samples.data_ptr<int64_t>();

    // Launch CUDA kernel
    launch_top_p_sampling(
        probs_ptr,
        top_p_ptr,
        samples_ptr,
        static_cast<int>(batch_size),
        static_cast<int>(vocab_size),
        0  // Use default stream
    );

    // Synchronize to ensure completion and check for errors
    cudaError_t err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        throw std::runtime_error("CUDA kernel execution failed: " + 
                                 std::string(cudaGetErrorString(err)));
    }
}

// Alternative run function that returns tensor (for compatibility)
torch::Tensor run_with_return(torch::Tensor probs, torch::Tensor top_p) {
    // Validate inputs
    validate_tensor(probs, "probs", torch::kFloat32, torch::kCUDA, 2);
    validate_tensor(top_p, "top_p", torch::kFloat32, torch::kCUDA, 1);

    // Get dimensions
    int64_t batch_size = probs.size(0);
    int64_t vocab_size = probs.size(1);

    // Validate vocab_size matches expected constant
    if (vocab_size != 151936) {
        throw std::runtime_error("vocab_size must be 151936, got " + 
                                 std::to_string(vocab_size));
    }

    // Validate top_p size matches batch_size
    if (top_p.size(0) != batch_size) {
        throw std::runtime_error("top_p batch size must match probs batch size");
    }

    // Validate batch_size is positive
    if (batch_size <= 0) {
        throw std::runtime_error("batch_size must be positive, got " + 
                                 std::to_string(batch_size));
    }

    // Create output tensor on CUDA device using TensorOptions
    torch::Tensor samples = torch::empty({batch_size}, torch::TensorOptions()
        .dtype(torch::kInt64)
        .device(torch::kCUDA));

    // Get raw pointers
    const float* probs_ptr = probs.data_ptr<float>();
    const float* top_p_ptr = top_p.data_ptr<float>();
    int64_t* samples_ptr = samples.data_ptr<int64_t>();

    // Launch CUDA kernel
    launch_top_p_sampling(
        probs_ptr,
        top_p_ptr,
        samples_ptr,
        static_cast<int>(batch_size),
        static_cast<int>(vocab_size),
        0  // Use default stream
    );

    // Synchronize to ensure completion and check for errors
    cudaError_t err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        throw std::runtime_error("CUDA kernel execution failed: " + 
                                 std::string(cudaGetErrorString(err)));
    }

    return samples;
}

// PyBind11 module definition - support both signatures
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "Top-p sampling CUDA kernel for A800 GPU";

    // Primary signature: accepts output tensor (in-place operation)
    m.def("run", &run, "Execute top-p sampling on probability distributions (in-place)",
          py::arg("probs"), py::arg("top_p"), py::arg("samples"));

    // Alternative signature: returns output tensor
    m.def("run_with_return", &run_with_return, "Execute top-p sampling and return results",
          py::arg("probs"), py::arg("top_p"));
}
